#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long gcd(long long a, long long b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

long long lcm(long long a, long long b) {
    return (a * b) / gcd(a, b);
}

long long powmod(long long base, long long exponent, long long mod) {
    long long result = 1;
    while (exponent > 0) {
        if (exponent % 2 == 1) result = (result * base) % mod;
        exponent /= 2;
        base = (base * base) % mod;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, L, R;
        scanf("%d %d %d %d", &N, &M, &L, &R);
        long long sum = 0;
        for (int D = L; D <= R; D++) {
            long long count = 0;
            for (int mask = 0; mask < (1 << M); mask++) {
                long long lcm_val = 1;
                int num = 0;
                for (int i = 0; i < M; i++) {
                    if ((mask & (1 << i)) != 0) {
                        lcm_val = lcm(lcm_val, i + 1);
                        num++;
                    }
                }
                if (lcm_val % D == 0 && num == N) count++;
            }
            sum = (sum + count) % MOD;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

